```class Solution {
public:
    int hammingDistance(int x, int y) {
        int result = 0;
        while (x != 0) {
            result++;
            x &= x - 1;
        }
        while (y != 0) {
            result++;
            y &= y - 1;
        }
        return result;
    }
};```

